	d_finavalu[offset_ecc+36] = d_finavalu[offset_ecc+36] + 1e-3*d_com[1];
	d_finavalu[offset_ecc+37] = d_finavalu[offset_ecc+37] + 1e-3*d_com[2];

	Vmyo = 2.1454e-11;
	Vdyad = 1.7790e-14;
	VSL = 6.6013e-13;

	kSLmyo = 8.587e-15;
	k0Boff = 0.0014;
	k0Bon = k0Boff/0.2;
	k2Boff = k0Boff/100;
	k2Bon = k0Bon;

	k4Bon = k0Bon;
	CaMtotDyad = d_initvalu[offset_Dyad+0] + d_initvalu[offset_Dyad+1] + d_initvalu[offset_Dyad+2] + d_initvalu[offset_Dyad+3] + d_initvalu[offset_Dyad+4] + d_initvalu[offset_Dyad+5] + CaMKIItotDyad * (d_initvalu[offset_Dyad+6] + d_initvalu[offset_Dyad+7] + d_initvalu[offset_Dyad+8] + d_initvalu[offset_Dyad+9]) + d_initvalu[offset_Dyad+12] + d_initvalu[offset_Dyad+13] + d_initvalu[offset_Dyad+14];
	Bdyad = BtotDyad - CaMtotDyad;
	J_cam_dyadSL = 1e-3 * (k0Boff*d_initvalu[offset_Dyad+0] - k0Bon*Bdyad*d_initvalu[offset_SL+0]);
	J_ca2cam_dyadSL = 1e-3 * (k2Boff*d_initvalu[offset_Dyad+1] - k2Bon*Bdyad*d_initvalu[offset_SL+1]);
	J_ca4cam_dyadSL = 1e-3 * (k2Boff*d_initvalu[offset_Dyad+2] - k4Bon*Bdyad*d_initvalu[offset_SL+2]);

	J_cam_SLmyo = kSLmyo * (d_initvalu[offset_SL+0] - d_initvalu[offset_Cyt+0]);
	J_ca2cam_SLmyo = kSLmyo * (d_initvalu[offset_SL+1] - d_initvalu[offset_Cyt+1]);
	J_ca4cam_SLmyo = kSLmyo * (d_initvalu[offset_SL+2] - d_initvalu[offset_Cyt+2]);

	d_finavalu[offset_Dyad+0] = d_finavalu[offset_Dyad+0] - J_cam_dyadSL;
	d_finavalu[offset_Dyad+1] = d_finavalu[offset_Dyad+1] - J_ca2cam_dyadSL;
	d_finavalu[offset_Dyad+2] = d_finavalu[offset_Dyad+2] - J_ca4cam_dyadSL;

	d_finavalu[offset_SL+0] = d_finavalu[offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
	d_finavalu[offset_SL+1] = d_finavalu[offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
	d_finavalu[offset_SL+2] = d_finavalu[offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

	d_finavalu[offset_Cyt+0] = d_finavalu[offset_Cyt+0] + J_cam_SLmyo/Vmyo;
	d_finavalu[offset_Cyt+1] = d_finavalu[offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
	d_finavalu[offset_Cyt+2] = d_finavalu[offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

void kernel_2(fp timeinst, fp* initvalu, fp* params, fp* finavalu, fp* com) {
	fp CaDyad, CaSL, CaCyt;

	ecc(timeinst, initvalu, 0, params, 0, finavalu);

	CaDyad = initvalu[35]*1e3;
	cam(timeinst, initvalu, 46, params, 0, finavalu, CaDyad);
	com[0] = finavalu[46+15];

	CaSL = initvalu[36]*1e3;
	cam(timeinst, initvalu, 61, params, 5, finavalu, CaSL);
	com[1] = finavalu[61+15];

	CaCyt = initvalu[37]*1e3;
	cam(timeinst, initvalu, 76, params, 10, finavalu, CaCyt);
	com[2] = finavalu[76+15];

	kernel_fin_2(initvalu, finavalu, 0, 46, 61, 76, params, com);

	int i;
	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){
			finavalu[i] = 0.0001;
		}
		else if (isinf(finavalu[i]) == 1){
			finavalu[i] = 0.0001;
		}
	}
}

void embedded_fehlberg_7_8_2(fp h, fp timeinst, fp* initvalu, fp* finavalu, fp* parameter, fp* error, fp* initvalu_temp, fp* finavalu_temp, fp* com) {
	const fp c_1_11 = 41.0 / 840.0;
	const fp c6 = 34.0 / 105.0;
	const fp c_7_8 = 9.0 / 35.0;
	const fp c_9_10 = 9.0 / 280.0;

	const fp a2 = 2.0 / 27.0;
	const fp a3 = 1.0 / 9.0;
	const fp a4 = 1.0 / 6.0;
	const fp a5 = 5.0 / 12.0;
	const fp a6 = 1.0 / 2.0;
	const fp a7 = 5.0 / 6.0;
	const fp a8 = 1.0 / 6.0;
	const fp a9 = 2.0 / 3.0;
	const fp a10 = 1.0 / 3.0;

	const fp b31 = 1.0 / 36.0;
	const fp b32 = 3.0 / 36.0;
	const fp b41 = 1.0 / 24.0;
	const fp b43 = 3.0 / 24.0;
	const fp b51 = 20.0 / 48.0;
	const fp b53 = -75.0 / 48.0;
	const fp b54 = 75.0 / 48.0;
	const fp b61 = 1.0 / 20.0;
	const fp b64 = 5.0 / 20.0;
	const fp b65 = 4.0 / 20.0;
	const fp b71 = -25.0 / 108.0;
	const fp b74 = 125.0 / 108.0;
	const fp b75 = -260.0 / 108.0;
	const fp b76 = 250.0 / 108.0;
	const fp b81 = 31.0/300.0;
	const fp b85 = 61.0/225.0;
	const fp b86 = -2.0/9.0;
	const fp b87 = 13.0/900.0;
	const fp b91 = 2.0;
	const fp b94 = -53.0/6.0;
	const fp b95 = 704.0 / 45.0;
	const fp b96 = -107.0 / 9.0;
	const fp b97 = 67.0 / 90.0;
	const fp b98 = 3.0;
	const fp b10_1 = -91.0 / 108.0;
	const fp b10_4 = 23.0 / 108.0;
	const fp b10_5 = -976.0 / 135.0;
	const fp b10_6 = 311.0 / 54.0;
	const fp b10_7 = -19.0 / 60.0;
	const fp b10_8 = 17.0 / 6.0;
	const fp b10_9 = -1.0 / 12.0;
	const fp b11_1 = 2383.0 / 4100.0;
	const fp b11_4 = -341.0 / 164.0;
	const fp b11_5 = 4496.0 / 1025.0;
	const fp b11_6 = -301.0 / 82.0;
	const fp b11_7 = 2133.0 / 4100.0;
	const fp b11_8 = 45.0 / 82.0;
	const fp b11_9 = 45.0 / 164.0;
	const fp b11_10 = 18.0 / 41.0;
	const fp b12_1 = 3.0 / 205.0;
	const fp b12_6 = -6.0 / 41.0;
	const fp b12_7 = -3.0 / 205.0;
	const fp b12_8 = -3.0 / 41.0;
	const fp b12_9 = 3.0 / 41.0;
	const fp b12_10 = 6.0 / 41.0;
	const fp b13_1 = -1777.0 / 4100.0;
	const fp b13_4 = -341.0 / 164.0;
	const fp b13_5 = 4496.0 / 1025.0;
	const fp b13_6 = -289.0 / 82.0;
	const fp b13_7 = 2193.0 / 4100.0;
	const fp b13_8 = 51.0 / 82.0;
	const fp b13_9 = 33.0 / 164.0;
	const fp b13_10 = 12.0 / 41.0;

	const fp err_factor = -41.0 / 840.0;

	fp h2_7 = a2 * h;
	fp timeinst_temp;
	int i, j;

	for(j=0; j<13; j++){
		if(j==0){
			timeinst_temp = timeinst;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i];
			}
		}
		else if(j==1){
			timeinst_temp = timeinst+h2_7;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h2_7 * (finavalu_temp[0*EQUATIONS+i]);
			}
		}
		else if(j==2){
			timeinst_temp = timeinst+a3*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b31*finavalu_temp[0*EQUATIONS+i] + b32*finavalu_temp[1*EQUATIONS+i]);
			}
		}
		else if(j==3){
			timeinst_temp = timeinst+a4*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b41*finavalu_temp[0*EQUATIONS+i] + b43*finavalu_temp[2*EQUATIONS+i]);
			}
		}
		else if(j==4){
			timeinst_temp = timeinst+a5*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b51*finavalu_temp[0*EQUATIONS+i] + b53*finavalu_temp[2*EQUATIONS+i] + b54*finavalu_temp[3*EQUATIONS+i]);
			}
		}
		else if(j==5){
			timeinst_temp = timeinst+a6*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b61*finavalu_temp[0*EQUATIONS+i] + b64*finavalu_temp[3*EQUATIONS+i] + b65*finavalu_temp[4*EQUATIONS+i]);
			}
		}
		else if(j==6){
			timeinst_temp = timeinst+a7*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b71*finavalu_temp[0*EQUATIONS+i] + b74*finavalu_temp[3*EQUATIONS+i] + b75*finavalu_temp[4*EQUATIONS+i] + b76*finavalu_temp[5*EQUATIONS+i]);
			}
		}
		else if(j==7){
			timeinst_temp = timeinst+a8*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b81*finavalu_temp[0*EQUATIONS+i] + b85*finavalu_temp[4*EQUATIONS+i] + b86*finavalu_temp[5*EQUATIONS+i] + b87*finavalu_temp[6*EQUATIONS+i]);
			}
		}
		else if(j==8){
			timeinst_temp = timeinst+a9*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b91*finavalu_temp[0*EQUATIONS+i] + b94*finavalu_temp[3*EQUATIONS+i] + b95*finavalu_temp[4*EQUATIONS+i] + b96*finavalu_temp[5*EQUATIONS+i] + b97*finavalu_temp[6*EQUATIONS+i]+ b98*finavalu_temp[7*EQUATIONS+i]);
			}
		}
		else if(j==9){
			timeinst_temp = timeinst+a10*h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b10_1*finavalu_temp[0*EQUATIONS+i] + b10_4*finavalu_temp[3*EQUATIONS+i] + b10_5*finavalu_temp[4*EQUATIONS+i] + b10_6*finavalu_temp[5*EQUATIONS+i] + b10_7*finavalu_temp[6*EQUATIONS+i] + b10_8*finavalu_temp[7*EQUATIONS+i] + b10_9*finavalu_temp[8*EQUATIONS+i]);
			}
		}
		else if(j==10){
			timeinst_temp = timeinst+h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b11_1*finavalu_temp[0*EQUATIONS+i] + b11_4*finavalu_temp[3*EQUATIONS+i] + b11_5*finavalu_temp[4*EQUATIONS+i] + b11_6*finavalu_temp[5*EQUATIONS+i] + b11_7*finavalu_temp[6*EQUATIONS+i] + b11_8*finavalu_temp[7*EQUATIONS+i] + b11_9*finavalu_temp[8*EQUATIONS+i]+ b11_10 * finavalu_temp[9*EQUATIONS+i]);
			}
		}
		else if(j==11){
			timeinst_temp = timeinst;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b12_1*finavalu_temp[0*EQUATIONS+i] + b12_6*finavalu_temp[5*EQUATIONS+i] + b12_7*finavalu_temp[6*EQUATIONS+i] + b12_8*finavalu_temp[7*EQUATIONS+i] + b12_9*finavalu_temp[8*EQUATIONS+i] + b12_10 * finavalu_temp[9*EQUATIONS+i]);
			}
		}
		else if(j==12){
			timeinst_temp = timeinst+h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * (b13_1*finavalu_temp[0*EQUATIONS+i] + b13_4*finavalu_temp[3*EQUATIONS+i] + b13_5*finavalu_temp[4*EQUATIONS+i] + b13_6*finavalu_temp[5*EQUATIONS+i] + b13_7*finavalu_temp[6*EQUATIONS+i] + b13_8*finavalu_temp[7*EQUATIONS+i] + b13_9*finavalu_temp[8*EQUATIONS+i] + b13_10*finavalu_temp[9*EQUATIONS+i] + finavalu_temp[11*EQUATIONS+i]);
			}
		}

		kernel_2(timeinst_temp, initvalu_temp, parameter, &finavalu_temp[j*EQUATIONS], com);
	}

	for(i=0; i<EQUATIONS; i++){
		finavalu[i] = initvalu[i] + h * (c_1_11 * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i]) + c6 * finavalu_temp[5*EQUATIONS+i] + c_7_8 * (finavalu_temp[6*EQUATIONS+i] + finavalu_temp[7*EQUATIONS+i]) + c_9_10 * (finavalu_temp[8*EQUATIONS+i] + finavalu_temp[9*EQUATIONS+i]));
	}

	for(i=0; i<EQUATIONS; i++){
		error[i] = fabs(err_factor * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i] - finavalu_temp[11*EQUATIONS+i] - finavalu_temp[12*EQUATIONS+i]));
	}
}

#define max(x,y) ((x) < (y) ? (y) : (x))
#define min(x,y) ((x) < (y) ? (x) : (y))
#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125
#define MAX_SCALE_FACTOR 4.0

void solver_2(int workload, int xmax, fp* x, fp* y, fp* params, fp* com, fp* err, fp* scale, fp* yy, fp* initvalu_temp, fp* finavalu_temp) {
	fp err_exponent;
	fp h_init;
	fp h;
	fp tolerance;
	int xmin;
	int error;
	int outside;
	fp scale_min;
	fp scale_fina;
	int i, j, k;
	long y_pointer_initial;
	long y_pointer_current;
	long x_pointer_current;
	int err_pointer;
	int scale_pointer;
	int yy_pointer;
	int params_pointer;
	int initvalu_temp_pointer;
	int finavalu_temp_pointer;
	int com_pointer;
	int tid;

#pragma omp parallel for
	for(tid = 0; tid < workload; tid++) {
		err_pointer = tid*EQUATIONS;
		scale_pointer = tid*EQUATIONS;
		yy_pointer = tid*EQUATIONS;
		params_pointer = tid*PARAMETERS;
		initvalu_temp_pointer = tid*EQUATIONS;
		finavalu_temp_pointer = tid*13*EQUATIONS;
		com_pointer = tid*3;

		err_exponent = 1.0 / 7.0;
		h_init = 1;
		h = h_init;
		xmin = 0;
		tolerance = 10 / (fp)(xmax - xmin);

		if (xmax < xmin || h <= 0.0){
			continue;
		}
		if (xmax == xmin){
			continue;
		}
		if (h > (xmax - xmin)){
			h = (fp)xmax - (fp)xmin;
		}

		for(k=1; k<(xmax+1); k++) {
			y_pointer_initial = tid*((xmax+1)*EQUATIONS)+(k-1)*EQUATIONS;
			y_pointer_current = tid*((xmax+1)*EQUATIONS)+k*EQUATIONS;
			x_pointer_current = tid*(xmax+1)+k;

			x[x_pointer_current] = (fp)k;
			h = h_init;
			scale_fina = 1.0;

			for (j = 0; j < ATTEMPTS; j++) {
				error = 0;
				outside = 0;
				scale_min = MAX_SCALE_FACTOR;

				embedded_fehlberg_7_8_2(h, x[x_pointer_current], &y[y_pointer_initial], &y[y_pointer_current], &params[params_pointer], &err[err_pointer], &initvalu_temp[initvalu_temp_pointer], &finavalu_temp[finavalu_temp_pointer], &com[com_pointer]);

				for(i=0; i<EQUATIONS; i++){
					if(err[err_pointer+i] > 0){
						error = 1;
					}
				}
				if (error != 1) {
					scale_fina = MAX_SCALE_FACTOR;
					break;
				}

				for(i=0; i<EQUATIONS; i++){
					if(y[y_pointer_initial+i] == 0.0){
						yy[yy_pointer+i] = tolerance;
					}
					else{
						yy[yy_pointer+i] = fabs(y[y_pointer_initial+i]);
					}
					scale[scale_pointer+i] = 0.8 * pow(tolerance * yy[yy_pointer+i] / err[err_pointer+i], err_exponent);
					if(scale[scale_pointer+i]<scale_min){
						scale_min = scale[scale_pointer+i];
					}
				}
				scale_fina = min(max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

				for(i=0; i<EQUATIONS; i++){
					if (err[err_pointer+i] > (tolerance * yy[yy_pointer+i])){
						outside = 1;
					}
				}
				if (outside == 0){
					break;
				}

				h = h * scale_fina;
				if (h >= 0.9) {
					h = 0.9;
				}
				if (x[x_pointer_current] + h > (fp)xmax){
					h = (fp)xmax - x[x_pointer_current];
				}
				else if (x[x_pointer_current] + h + 0.5 * h > (fp)xmax){
					h = 0.5 * h;
				}
			}

			x[x_pointer_current] = x[x_pointer_current] + h;

			if (j >= ATTEMPTS) {
				continue;
			}
		}
	}
}

int work_2(int xmax, int workload) {
	long long time0, time1, time2, time3, time4, time5, time6;
	long memory;
	int i;
	int pointer;
	fp* y;
	fp* d_y;
	long y_mem;
	fp* x;
	fp* d_x;
	long x_mem;
	fp* params;
	fp* d_params;
	int params_mem;
	fp* d_com;
	int com_mem;
	fp* d_err;
	int err_mem;
	fp* d_scale;
	int scale_mem;
	fp* d_yy;
	int yy_mem;
	fp* d_initvalu_temp;
	int initvalu_temp_mem;
	fp* d_finavalu_temp;
	int finavalu_temp_mem;

	time0 = get_time();

	time1 = get_time();

	memory = workload*(xmax+1)*EQUATIONS*4;
	if(memory>1000000000){
		printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
		return 0;
	}

	y_mem = workload * (xmax+1) * EQUATIONS * sizeof(fp);
	y = (fp *) malloc(y_mem);
	d_y = (fp *) malloc(y_mem);

	x_mem = workload * (xmax+1) * sizeof(fp);
	x = (fp *) malloc(x_mem);
	d_x = (fp *) malloc(x_mem);

	params_mem = workload * PARAMETERS * sizeof(fp);
	params = (fp *) malloc(params_mem);
	d_params = (fp *) malloc(params_mem);

	com_mem = workload * 3 * sizeof(fp);
	d_com = (fp *) malloc(com_mem);

	err_mem = workload * EQUATIONS * sizeof(fp);
	d_err = (fp *) malloc(err_mem);

	scale_mem = workload * EQUATIONS * sizeof(fp);
	d_scale = (fp *) malloc(scale_mem);

	yy_mem = workload * EQUATIONS * sizeof(fp);
	d_yy = (fp *) malloc(yy_mem);

	initvalu_temp_mem = workload * EQUATIONS * sizeof(fp);
	d_initvalu_temp = (fp *) malloc(initvalu_temp_mem);

	finavalu_temp_mem = workload * 13* EQUATIONS * sizeof(fp);
	d_finavalu_temp = (fp *) malloc(finavalu_temp_mem);

	time2 = get_time();

	for(i=0; i<workload; i++){
		pointer = i * (xmax+1) + 0;
		x[pointer] = 0;
	}

	for(i=0; i<workload; i++){
		pointer = i*((xmax+1)*EQUATIONS) + 0*(EQUATIONS);
		read("../../data/myocyte/y.txt", &y[pointer], 91, 1, 0);
	}

	for(i=0; i<workload; i++){
		pointer = i*PARAMETERS;
		read("../../data/myocyte/params.txt", &params[pointer], 18, 1, 0);
	}

	time3 = get_time();

	solver_2(workload, xmax, d_x, d_y, d_params, d_com, d_err, d_scale, d_yy, d_initvalu_temp, d_finavalu_temp);

	time4 = get_time();

	for(i=0; i<workload*(xmax+1)*EQUATIONS; i++){
		x[i] = d_x[i];
		y[i] = d_y[i];
	}

	time5 = get_time();

	free(y);
	free(d_y);
	free(x);
	free(d_x);
	free(params);
	free(d_params);
	free(d_com);
	free(d_err);
	free(d_scale);
	free(d_yy);
	free(d_initvalu_temp);
	free(d_finavalu_temp);

	time6 = get_time();

	printf("Time spent in different stages of the application:\n");
	printf("%.12f s, %.12f % : SETUP VARIABLES\n", (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : ALLOCATE CPU MEMORY AND GPU MEMORY\n", (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : READ DATA FROM FILES, COPY TO GPU MEMORY\n", (float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : RUN GPU KERNEL\n", (float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : COPY GPU DATA TO CPU MEMORY\n", (float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%.12f s, %.12f % : FREE MEMORY\n", (float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float) (time6-time0) / 1000000);

	return 0;
}
